import React from 'react';
import { Alert } from 'react-native';

const API_URL = 'https://api.example.com';
const LOCAL_IOT_URL = 'http://192.168.x.x';

const fetchWithHeaders = async (url, method = 'GET', body = null) => {
    const headers = {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
    };

    const options = {
        method,
        headers,
        body: body ? JSON.stringify(body) : null,
    };

    try {
        const response = await fetch(url, options);
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        return await response.json();
    } catch (error) {
        Alert.alert('Error', error.message);
        throw error;
    }
};

export const apiRequest = async (endpoint, method = 'GET', body = null) => {
    return await fetchWithHeaders(`${API_URL}${endpoint}`, method, body);
};

export const localIoTRequest = async (endpoint, method = 'GET', body = null) => {
    return await fetchWithHeaders(`${LOCAL_IOT_URL}${endpoint}`, method, body);
};

